        self.owner = owner
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            print(f"Added {amount} to the balance")
        return self.balance

    def withdraw(self, amount):
        if 0 < amount <= self.balance:
            self.balance -= amount
            print(f"Withdrew {amount}")
        else:
            print("Insufficient funds!")
        return self.balance

def process_temperatures(celsius_data):
    # Convert a list of Celsius temperatures to Fahrenheit using dictionary comprehension
    fahrenheit_dict = {f"Day_{i+1}": (temp * 9/5) + 32 for i, temp in enumerate(celsius_data)}

    hottest_day = max(fahrenheit_dict, key=fahrenheit_dict.get)
    average_temp = sum(fahrenheit_dict.values()) / len(fahrenheit_dict)

    return {
        "data": fahrenheit_dict,
        "hottest": hottest_day,
        "average": round(average_temp, 2)
    }

